from flask import Flask, request, session, jsonify
import redis
import functools
import time

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

@app.before_request
def check_session():
    if 'user_id' in session:
        # Extend session expiry
        redis_client.expire(f"session:{session['user_id']}", 3600)

@app.route('/login', methods=['POST'])
def login():
    user_id = request.json.get('user_id')
    if user_id:
        session['user_id'] = user_id
        # Store session in Redis
        redis_client.setex(f"session:{user_id}", 3600, "active")
        return jsonify({"status": "success"})
    return jsonify({"status": "failed"}), 401

@app.route('/logout', methods=['POST'])
def logout():
    user_id = session.get('user_id')
    if user_id:
        redis_client.delete(f"session:{user_id}")
        session.clear()
    return jsonify({"status": "logged_out"})

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({"data": cached_result, "cached": True})
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            return jsonify({"data": result, "cached": False})
        return wrapper
    return decorator

@app.route('/expensive-query')
@cache_result(expiration=600)
def expensive_query():
    # Simulate expensive database query
    time.sleep(2)
    return {"result": "expensive_data", "timestamp": time.time()}

if __name__ == '__main__':
    app.run(debug=False)